[FormControlEventHandler(formControlStr(SalesTable, ButtonInterCompanyPurchTableTP), FormControlEventType::Clicked)]
public static void ButtonInterCompanyPurchTableTP_OnClicked(FormControl sender, FormControlEventArgs e)
{
    SalesTable        salesTable = sender.formRun().dataSource('SalesTable').cursor();
    PurchTable        purchtable;

    MenuFunction menuFunction = new MenuFunction(menuitemdisplaystr(PurchTable), MenuItemType::Display);
    Args args  = new Args();
    purchtable = PurchTable::find(salesTable.ETG_TPPurchId);
    args.record(purchtable);
    menuFunction.run(args);
}

