private static void createLookup(FormReferenceGroupControl _ctrl)
{
    SysReferenceTableLookup     sysTableLookup  = SysReferenceTableLookup::newParameters(tablenum(LogisticsPostalAddress), _ctrl);
    Query                       lookupQuery = new Query();
    QuerybuildDatasource        qbd, qbd1, qbd2;

    qbd     = lookupQuery.addDataSource(tablenum(LogisticsPostalAddress));
    qbd1    = qbd.addDataSource(tablenum(DirPartyLocation));
    qbd1.addLink(fieldNum(LogisticsPostalAddress, Location), fieldNum(DirPartyLocation, Location));
    qbd1.joinMode(JoinMode::InnerJoin);

    qbd2 = qbd1.addDataSource(tablenum(CompanyInfo));
    qbd2.addLink(fieldNum(DirPartyLocation, Party), (fieldNum(CompanyInfo, RecId)));
    qbd2.joinMode(JoinMode::InnerJoin);

    qbd2.addRange(fieldnum(CompanyInfo, DataArea)).value(SysQuery::value(curext()));

    sysTableLookup.addLookupfield(fieldNum(LogisticsPostalAddress, Location));
    sysTableLookup.addLookupfield(fieldNum(LogisticsPostalAddress, Street));

    sysTableLookup.parmQuery(lookupQuery);
    sysTableLookup.performFormLookup();
}

/// <summary>
/// lookup method for reference sales order
/// </summary>
[FormControlEventHandler(formControlStr(SalesTable, SalesLine_ETGRefSalesId), FormControlEventType::Lookup)]
public static void SalesLine_ETGRefSalesId_OnLookup(FormControl sender, FormControlEventArgs e)
{
    Query query = new Query();
    QueryBuildDataSource queryBuildDataSource;
    QueryBuildRange queryBuildRange,qbr;
    FormRun     formRun = sender.formRun();
    SalesTable  salesTable = formRun.dataSource(1).cursor();

    SysTableLookup sysTableLookup = SysTableLookup::newParameters(tableNum(SalesTable), sender);

    sysTableLookup.addLookupField(fieldNum(SalesTable, SalesId));
    sysTableLookup.addLookupField(fieldNum(SalesTable, CustAccount));        
    sysTableLookup.addLookupField(fieldNum(SalesTable, SalesName));

    queryBuildDataSource = query.addDataSource(tableNum(SalesTable));

    //queryBuildRange = queryBuildDataSource.addRange(fieldNum(SalesTable, SalesId));
    //queryBuildRange.value(SysQuery::valueNot(salesTable.SalesId));

    qbr = queryBuildDataSource.addRange(fieldNum(SalesTable, CustAccount));
    qbr.value(salesTable.CustAccount);
    qbr.status(RangeStatus::Locked);

    sysTableLookup.parmQuery(query);
    sysTableLookup.performFormLookup();

    FormControlCancelableSuperEventArgs ce = e as FormControlCancelableSuperEventArgs;
    ce.CancelSuperCall();
}

[FormControlEventHandler(formControlStr(SalesTable, BuyerDeliveryRef), FormControlEventType::Lookup)]
public static void  BuyerDeliveryRef_OnLookup(FormControl sender, FormControlEventArgs e)
{
    FormDataSource          salesTable_ds       = sender.formRun().dataSource('ETG_SalesTableTrade');
    ETG_SalesTableTrade    salesTableTradeETG   = salesTable_ds.cursor();

    ETG_SalesTableHandlers::buyerLookup(sender,salesTableTradeETG.BuyerAccountNum);

    FormControlCancelableSuperEventArgs cancelableArgs = e as FormControlCancelableSuperEventArgs;
    cancelableArgs.CancelSuperCall();
}

private static void buyerLookup(FormReferenceGroupControl _ctrl,CustAccount _custAccount)
{
    SysReferenceTableLookup     sysTableLookup  = SysReferenceTableLookup::newParameters(tablenum(LogisticsPostalAddress), _ctrl);
    Query                       lookupQuery = new Query();
    QuerybuildDatasource        qbd, qbd1, qbd2;

    qbd     = lookupQuery.addDataSource(tablenum(LogisticsPostalAddress));
    qbd1    = qbd.addDataSource(tablenum(DirPartyLocation));
    qbd1.addLink(fieldNum(LogisticsPostalAddress, Location), fieldNum(DirPartyLocation, Location));
    qbd1.joinMode(JoinMode::InnerJoin);

    qbd2 = qbd1.addDataSource(tablenum(CustTable));
    qbd2.addLink(fieldNum(DirPartyLocation, Party), (fieldNum(CustTable, Party)));
    qbd2.joinMode(JoinMode::InnerJoin);

    qbd2.addRange(fieldnum(CustTable, AccountNum)).value(SysQuery::value(_custAccount));

    sysTableLookup.addLookupfield(fieldNum(LogisticsPostalAddress, Location));
    sysTableLookup.addLookupfield(fieldNum(LogisticsPostalAddress, Street));

    sysTableLookup.parmQuery(lookupQuery);
    sysTableLookup.performFormLookup();
}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(SalesTable, ETG_SalesLineQualityGrp_GroupId), FormControlEventType::Modified)]
public static void ETG_SalesLineQualityGrp_GroupId_OnModified(FormControl sender, FormControlEventArgs e)
{
    SalesLine                          salesLine;
    ETG_PostPackingQualityGrp          postPackingQualityGrp;
    ETG_QualitySubGrpView              qualitySubGrpView;
    Name        grpId   = sender.valueStr();

    FormDataSource  salesLine_ds   = sender.formRun().dataSource(formDataSourceStr(SalesTable,SalesLine))  as FormDataSource;
    salesLine                      = salesLine_ds.cursor();

    while select * from qualitySubGrpView
        where qualitySubGrpView.GroupID == grpId
    {
        postPackingQualityGrp.MinRange       = qualitySubGrpView.MinRange;
        postPackingQualityGrp.MaxRange       = qualitySubGrpView.MaxRange;
        postPackingQualityGrp.AdjustmentType = qualitySubGrpView.AdjustmentType;
        postPackingQualityGrp.Increment      = qualitySubGrpView.Increment;
        postPackingQualityGrp.FixedValue     = qualitySubGrpView.FixedValue;
        postPackingQualityGrp.SubGroupID     = qualitySubGrpView.SubGroupID;
        postPackingQualityGrp.InventTransId  = salesLine.InventTransId;
        postPackingQualityGrp.GroupID               = qualitySubGrpView.GroupID;
        postPackingQualityGrp.GroupDescription      = qualitySubGrpView.GroupDescription;
        postPackingQualityGrp.SubGroupDescription   = qualitySubGrpView.SubGroupDescription;
        postPackingQualityGrp.insert();
    }
}

/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(SalesTable, Notifytodifferentparty), FormControlEventType::Modified)]
public static void Notifytodifferentparty_OnModified(FormControl sender, FormControlEventArgs e)
{
    ETG_SalesTableTrade salesTableTradeETG = sender.formRun().dataSource().cursor();
    FormRun             element       = sender.formRun(); 
    FormControl         NotifyName   = element.design(0).controlName('NotifyName');
    FormControl         NotifyAddress   = element.design(0).controlName('NotifyAddress');

    if(salesTableTradeETG.Notifytodifferentparty == NoYes::Yes)
    {
        NotifyName.enabled(true);
        NotifyAddress.enabled(true);
    }
    else if(salesTableTradeETG.Notifytodifferentparty == NoYes::No)
    {
        salesTableTradeETG.Name = '';
        salesTableTradeETG.Address = '';
        NotifyName.enabled(false);
        NotifyAddress.enabled(false);
    }
}

