/// <param name="e"></param>
[FormControlEventHandler(formControlStr(SalesTable, BuyerBankString), FormControlEventType::Modified)]
public static void BuyerBankString_OnModified(FormControl sender, FormControlEventArgs e)
{
    ETG_SalesTableTrade salesTabletradeETG = sender.formRun().dataSource(FormDataSourcestr(SalesTable, ETG_SalesTableTrade)).cursor();
    FormDataSource      ETG_SalesTableTrade_ds =  sender.formRun().dataSource(FormDataSourcestr(SalesTable, ETG_SalesTableTrade));
    salesTabletradeETG.BuyerSecondaryBank = salesTabletradeETG.BuyerBank;

    if (salesTabletradeETG.BuyerSecondaryBank == '' || salesTabletradeETG.BuyerBank == '')
    {
        ETG_SalesTableTrade_ds.object(fieldNum(ETG_SalesTableTrade, BuyerSecondaryBank)).allowEdit(true);
    }
    else
    {
        ETG_SalesTableTrade_ds.object(fieldNum(ETG_SalesTableTrade, BuyerSecondaryBank)).allowEdit(false);
    }
}

