/// <summary>
///
/// </summary>
/// <param name="sender"></param>
/// <param name="e"></param>
[FormControlEventHandler(formControlStr(SalesTable, Through), FormControlEventType::Lookup)]
public static void Through_OnLookup(FormControl sender, FormControlEventArgs e)
{
    SysTableLookup          sysTableLookup = SysTableLookup::newParameters(tableNum(VendTable),sender);
    Query                   q   = new Query();
    QueryBuildDataSource    qbds,qbds1,qbds2,qbds3;
    QueryBuildRange         qbr;

    qbds   = q.addDataSource(tableNum(VendTable));
    qbds2 = qbds.addDataSource(tableNum(VendGroup));
    qbds2.joinMode(JoinMode::InnerJoin);
    qbds2.relations(true);
    qbds3    = qbds.addDataSource(tableNum(DirPartyTable)) ;
    qbds3.joinMode(JoinMode::InnerJoin);
    qbds3.addLink(fieldNum(VendTable, Party), fieldNum(DirPartyTable, RecId));


    qbr     = qbds2.addRange(fieldNum(VendGroup,ETG_Broker));
    qbr.value(queryValue(NoYes::Yes));

    sysTableLookup.addLookupfield(fieldNum(VendTable,AccountNum));
    sysTableLookup.addLookupfield(fieldNum(VendTable,vendgroup));
    sysTableLookup.addLookupfield(fieldNum(VendTable, Party), false);

    SysTableLookup.parmQuery(q);
    SysTableLookup.performFormLookup();
    FormControlCancelableSuperEventArgs ce = e as FormControlCancelableSuperEventArgs;

    ce.CancelSuperCall();

}

/// <summary>
[FormControlEventHandler(formControlStr(SalesTable, PlaceOfLoading), FormControlEventType::Modified)]
public static void PlaceOfLoading_OnModified(FormControl sender, FormControlEventArgs e)
{
    ETG_SalesTableTrade salesTabletradeETG = sender.formRun().dataSource(FormDataSourcestr(SalesTable, ETG_SalesTableTrade)).cursor();
    FormDataSource      ETG_SalesTableTrade_ds =  sender.formRun().dataSource(FormDataSourcestr(SalesTable, ETG_SalesTableTrade));
    ETG_PlaceOfLoading  placeofLoading;

    select firstonly placeofLoading
        where placeofLoading.PlaceOfLoading == salesTabletradeETG.PortOfLoading;
    salesTabletradeETG.PortOfLoadingDesc = placeofLoading.Description;

    if (salesTabletradeETG.PortOfLoadingDesc == '' || salesTabletradeETG.PortOfLoading == '')
    {
        ETG_SalesTableTrade_ds.object(fieldNum(ETG_SalesTableTrade, PortOfLoadingDesc)).allowEdit(true);
    }
    else
    {
        ETG_SalesTableTrade_ds.object(fieldNum(ETG_SalesTableTrade, PortOfLoadingDesc)).allowEdit(false);
    }

}

